async (page) => {
  var title = "图解 Blaze · Ch.11 批量 DML — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 11 章 · 批量 DML</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">UPDATE · DELETE · INSERT-SELECT · ReturningResult · 缓存一致性</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">逐行遍历实体、修改属性、逐个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">merge()</code>——当你需要把 10 万行的状态从 ACTIVE 改为 ARCHIVED 时，这种做法意味着 10 万次 SQL UPDATE。批量 DML 一条语句搞定，但 JPA 的原生批量操作只有字符串拼接的 JPQL，毫无类型安全。Blaze-Persistence 用 CriteriaBuilder 的流式 API 把 UPDATE、DELETE、INSERT-SELECT 统统变成编译时可检查的类型安全构建器。</p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">JPA 原生 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">executeUpdate()</code> 的局限：字符串拼接、无编译检查、重构不安全</li><li style=\"margin-bottom:4px;font-size:13px;\">UPDATE CriteriaBuilder：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">set()</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setExpression()</code> 流式设置列值 + WHERE 过滤</li><li style=\"margin-bottom:4px;font-size:13px;\">DELETE CriteriaBuilder：带子查询条件的批量删除</li><li style=\"margin-bottom:4px;font-size:13px;\">INSERT-SELECT：跨表数据迁移与归档的类型安全方式</li><li style=\"margin-bottom:4px;font-size:13px;\">ReturningResult：获取受影响的行数据，以及各数据库对 RETURNING 子句的支持差异</li><li style=\"margin-bottom:4px;font-size:13px;\">批量 DML 对 JPA 一级缓存的影响及解决方案</li><li style=\"margin-bottom:4px;font-size:13px;\">7 个常见陷阱：实体监听器失效、版本列不自增、JOIN 在 UPDATE/DELETE 中的兼容性等</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置知识：<span style=\"color:#1e6fff;\">第 3 章</span> CriteriaBuilder 查询引擎的基本用法（WHERE、表达式、子查询）。</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">11.1 JPA 批量操作的局限</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">JPA 规范提供了 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Query.executeUpdate()</code> 来执行批量 UPDATE 和 DELETE，但它接受的是原始 JPQL 字符串。当实体字段重命名时，编译器无法发现断裂的查询；当 WHERE 条件复杂化时，字符串拼接变成噩梦。</p></section>\n\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// JPA 原生批量 UPDATE — 字符串拼接</span><br/>String jpql = \"UPDATE Order o \" +<br/>    \"SET o.status = :newStatus \" +<br/>    \"WHERE o.status = :oldStatus \" +<br/>    \"AND o.createdAt &lt; :cutoff\";<br/>int count = em.createQuery(jpql)<br/>    .setParameter(\"newStatus\", Status.ARCHIVED)<br/>    .setParameter(\"oldStatus\", Status.COMPLETED)<br/>    .setParameter(\"cutoff\", cutoffDate)<br/>    .executeUpdate();<br/><span style=\"color:#6c7086;font-style:italic;\">// 字段名拼错？编译通过，运行时才爆炸</span></p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Blaze-Persistence 类型安全 UPDATE</span><br/>int count = cbf.update(em, Order.class)<br/>    .set(\"status\", Status.ARCHIVED)<br/>    .where(\"status\").eq(Status.COMPLETED)<br/>    .where(\"createdAt\").lt(cutoffDate)<br/>    .executeUpdate();<br/><span style=\"color:#6c7086;font-style:italic;\">// 字段名由编译器检查，IDE 可安全重构</span></p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">对比维度</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">JPA executeUpdate()</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Blaze-Persistence DML</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">查询构建</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">JPQL 字符串拼接</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">流式 Builder API</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">类型安全</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌ 运行时检查</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 编译时检查</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">IDE 重构</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌ 字符串内容不可追踪</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 字段引用可重构</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">子查询</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">手写嵌套 JPQL</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Builder 组合子查询</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">INSERT-SELECT</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌ JPA 不支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 原生支持</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">RETURNING 子句</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌ 不支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 支持（数据库相关）</td></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">11.2 UPDATE CriteriaBuilder</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 的 UPDATE 操作从 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory.update()</code> 开始，返回一个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">UpdateCriteriaBuilder</code>。它支持 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">set()</code> 设置字面值、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setExpression()</code> 设置表达式（如数学运算、函数调用），以及完整的 WHERE 子句过滤。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-2 · UPDATE 查询构建管线</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">cbf</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">update</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">e</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">设置列值</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">WHERE 条件</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">cbf.update(em, Entity.class)\"] --> ALIAS[\"设置别名 .from(Entity.class, 'e')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">设置别名 .from(Entity.class, 'e')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.set('col', literalValue)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.setExpression('col', 'UPPER(e.name)')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.set('col', subqueryBuilder)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.where('field').eq(val)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.where('field').in(subquery)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.whereExists(subquery)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.executeUpdate()</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">生成 SQL:<br/>UPDATE table SET ... WHERE ...</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">数据库执行<br/>返回 int affectedRows</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">基础 UPDATE：设置字面值</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 将所有过期订单标记为 CANCELLED</span><br/>int cancelled = cbf.update(em, Order.class, \"o\")<br/>    .set(\"status\", OrderStatus.CANCELLED)<br/>    .set(\"cancelReason\", \"auto-expired\")<br/>    .where(\"expiresAt\").le(LocalDateTime.now())<br/>    .where(\"status\").eq(OrderStatus.PENDING)<br/>    .executeUpdate();</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">表达式 UPDATE：setExpression()</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当需要基于现有值进行计算时，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setExpression()</code> 接受 JPQL 表达式字符串：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 所有商品价格上调 10%</span><br/>int updated = cbf.update(em, Product.class, \"p\")<br/>    .setExpression(\"price\", \"p.price * 1.10\")<br/>    .setExpression(\"updatedAt\", \"CURRENT_TIMESTAMP\")<br/>    .where(\"category\").eq(Category.ELECTRONICS)<br/>    .executeUpdate();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 set() vs setExpression()：</strong><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">set(\"price\", 100)</code> 将 price 设为字面值 100；<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setExpression(\"price\", \"p.price * 1.10\")</code> 将 price 设为当前值的 1.1 倍。前者绑定参数，后者嵌入表达式。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">带子查询的 UPDATE</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 将每个客户的 totalOrders 更新为实际订单数</span><br/>int synced = cbf.update(em, Customer.class, \"c\")<br/>    .set(\"totalOrders\")<br/>        .from(Order.class, \"o\")<br/>        .select(\"COUNT(o)\")<br/>        .where(\"o.customer.id\").eqExpression(\"c.id\")<br/>    .end()<br/>    .executeUpdate();</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">11.3 DELETE CriteriaBuilder</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">DELETE 操作的 API 更简洁——不需要 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">set()</code>，只有 WHERE 条件。<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">cbf.delete(em, Entity.class)</code> 返回 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">DeleteCriteriaBuilder</code>，支持所有 CriteriaBuilder 的 WHERE 功能，包括子查询、EXISTS 和复合条件。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-3 · DELETE 查询构建流程</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">cbf</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">delete</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">cbf.delete(em, Entity.class)\"] --> WHERE[\"WHERE 子句</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">WHERE 子句</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">.where('field').eq(val)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">.whereExists(subquery)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">.where('field').in(subquery)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">.executeUpdate()</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">DELETE FROM table WHERE ...</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">int affectedRows</p></section></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">简单批量删除</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 删除 90 天前的审计日志</span><br/>int deleted = cbf.delete(em, AuditLog.class, \"a\")<br/>    .where(\"createdAt\").lt(LocalDate.now().minusDays(90))<br/>    .executeUpdate();</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">带子查询的删除</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 删除没有任何订单的客户</span><br/>int purged = cbf.delete(em, Customer.class, \"c\")<br/>    .whereNotExists()<br/>        .from(Order.class, \"o\")<br/>        .select(\"1\")<br/>        .where(\"o.customer.id\").eqExpression(\"c.id\")<br/>    .end()<br/>    .executeUpdate();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-4 · 子查询 DELETE 的 SQL 生成过程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">DeleteCriteriaBuilder</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">JPQL 生成器</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">11.4 INSERT-SELECT</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">JPA 规范不支持 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">INSERT ... SELECT</code> 语法，这是 Blaze-Persistence 的独有扩展。它将一个查询的结果直接插入目标表，特别适合数据归档、表间迁移和批量初始化场景。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-5 · INSERT-SELECT 执行流程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">InsertCriteriaBuilder</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">查询引擎</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">数据归档示例</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 将已完成超过 1 年的订单归档到 ArchiveOrder 表</span><br/>int archived = cbf.insertInto(em, ArchiveOrder.class)<br/>    .from(Order.class, \"o\")<br/>    .bind(\"id\").select(\"o.id\")<br/>    .bind(\"orderNumber\").select(\"o.orderNumber\")<br/>    .bind(\"customerId\").select(\"o.customer.id\")<br/>    .bind(\"totalAmount\").select(\"o.totalAmount\")<br/>    .bind(\"originalStatus\").select(\"o.status\")<br/>    .bind(\"archivedAt\").select(\"CURRENT_TIMESTAMP\")<br/>    .where(\"o.status\").eq(OrderStatus.COMPLETED)<br/>    .where(\"o.completedAt\").lt(LocalDate.now().minusYears(1))<br/>    .executeUpdate();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 归档后删除原表数据</span><br/>int cleaned = cbf.delete(em, Order.class, \"o\")<br/>    .where(\"o.status\").eq(OrderStatus.COMPLETED)<br/>    .where(\"o.completedAt\").lt(LocalDate.now().minusYears(1))<br/>    .executeUpdate();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-6 · 归档流水线：INSERT-SELECT → DELETE</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">INSERT</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SELECT</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">orders 表<br/>(100万行)\"] -->|\"INSERT-SELECT<br/>筛选已完成 > 1年\"| ARCHIVE[\"archive_orders 表<br/>(+1250 行)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">archive_orders 表<br/>(+1250 行)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">orders 表<br/>(清理后 998,750 行)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">@Transactional</p></section></td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ INSERT-SELECT + DELETE 必须在同一事务：</strong>如果归档和删除不在同一事务中，中间发生故障会导致数据丢失（原表已删但归档未入库）或数据重复（归档成功但删除失败后重试）。始终用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Transactional</code> 包裹整个流程。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">11.5 ReturningResult</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">标准的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">executeUpdate()</code> 只返回受影响行数（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">int</code>）。但有时你需要知道<strong style=\"color:#1a1a2e;font-weight:700;\">具体哪些行</strong>被修改或删除了——例如删除后需要向被删用户发送通知。Blaze-Persistence 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ReturningResult</code> 机制利用 SQL 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">RETURNING</code> 子句来解决这个需求。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-7 · 各数据库对 RETURNING 子句的支持</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n✅ 原生支持\nPostgreSQL — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">RETURNING *</code><br/>Oracle — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">RETURNING INTO</code><br/>SQL Server — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OUTPUT</code> clause\n\n\n⚠️ 模拟支持\nH2 — 先 SELECT 再 DML<br/>MySQL — 先 SELECT 再 DML\n\n\n❌ 不支持\n旧版数据库<br/>需手动两步操作\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">DELETE + RETURNING：删除并获取被删数据</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 删除过期会话并返回被删的用户 ID</span><br/>ReturningResult&lt;Long&gt; result = cbf.delete(em, Session.class, \"s\")<br/>    .where(\"s.expiresAt\").lt(Instant.now())<br/>    .executeWithReturning(\"s.userId\");<br/><br/>int deletedCount = result.getUpdateCount();<br/>List&lt;Long&gt; affectedUserIds = result.getResultList();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 向被删用户发送\"会话过期\"通知</span><br/>notificationService.notifySessionExpired(affectedUserIds);</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">UPDATE + RETURNING</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 锁定待处理任务并返回任务 ID</span><br/>ReturningResult&lt;Long&gt; result = cbf.update(em, Task.class, \"t\")<br/>    .set(\"status\", TaskStatus.PROCESSING)<br/>    .set(\"lockedBy\", currentWorker)<br/>    .set(\"lockedAt\", Instant.now())<br/>    .where(\"status\").eq(TaskStatus.PENDING)<br/>    .where(\"priority\").ge(Priority.HIGH)<br/>    .executeWithReturning(\"t.id\");<br/><br/>List&lt;Long&gt; lockedTaskIds = result.getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-8 · RETURNING 模拟机制（MySQL / H2）</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">MySQL / H2</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 检测到数据库不支持原生 RETURNING</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 两步操作封装在同一事务中</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">📝 模拟模式的注意事项：</strong>对于不支持原生 RETURNING 的数据库，Blaze-Persistence 会先执行 SELECT 再执行 DML。这意味着两条 SQL 之间有微小的时间窗口，在高并发场景下可能产生竞态条件。生产环境建议优先选择支持原生 RETURNING 的数据库（PostgreSQL、Oracle、SQL Server）。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">11.6 JPA 缓存一致性</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">批量 DML 最大的\"暗坑\"是<strong style=\"color:#1a1a2e;font-weight:700;\">绕过了 JPA 持久化上下文（一级缓存）</strong>。当你用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">executeUpdate()</code> 直接在数据库中修改了 1000 行，EntityManager 里缓存的那些实体对象仍然是旧值——读到的是脏数据。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-9 · 批量 DML 导致的缓存不一致问题</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">JPA 持久化上下文 (一级缓存)</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order#1<br/>status = PENDING</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order#2<br/>status = PENDING</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order#3<br/>status = PENDING</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">数据库</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order#1<br/>status = ARCHIVED</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order#2<br/>status = ARCHIVED</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order#3<br/>status = ARCHIVED</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">批量 UPDATE<br/>SET status = ARCHIVED</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">💀 脏读</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">解决方案：DML 前后的 EntityManager 操作</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-10 · 批量 DML 的正确 EntityManager 生命周期</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">em</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">flush</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ncbf</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">update</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">clear</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">find</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">开始事务\"] --> B[\"em.flush()<br/>将待写变更推入数据库</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">em.flush()<br/>将待写变更推入数据库</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">执行批量 DML<br/>cbf.update/delete/insert</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 后续还需要<br/>读取被修改的实体？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">em.clear()<br/>清空持久化上下文</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">重新加载实体<br/> em.find() / 查询</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">直接提交事务</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">事务提交</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Transactional<br/>public void archiveOldOrders(LocalDate cutoff) {<br/>    <span style=\"color:#6c7086;font-style:italic;\">// ① flush：确保之前的实体变更先写入数据库</span><br/>    em.flush();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// ② 执行批量 DML</span><br/>    int count = cbf.update(em, Order.class, \"o\")<br/>        .set(\"status\", OrderStatus.ARCHIVED)<br/>        .where(\"status\").eq(OrderStatus.COMPLETED)<br/>        .where(\"completedAt\").lt(cutoff)<br/>        .executeUpdate();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// ③ clear：清空一级缓存，避免脏读</span><br/>    em.clear();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// ④ 后续查询会从数据库重新加载最新数据</span><br/>    List&lt;Order&gt; orders = cbf.create(em, Order.class)<br/>        .where(\"status\").eq(OrderStatus.ARCHIVED)<br/>        .getResultList();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 为什么 flush() 在 DML 之前？</strong>如果在批量 DML 前持久化上下文有未刷新的变更（比如刚 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">persist()</code> 的实体），这些变更可能被批量 DML 覆盖或冲突。<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">flush()</code> 确保\"先存后改\"的顺序一致性。\n</section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">时机</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">操作</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">目的</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">DML 之前</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">em.flush()</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">将持久化上下文中的 pending 变更写入数据库，避免被批量 DML 覆盖</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">DML 之后</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">em.clear()</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">清空一级缓存，后续查询从数据库获取最新数据</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">替代方案</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">新事务 / 新 EntityManager</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">在独立的持久化上下文中执行 DML，彻底隔离缓存</td></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">11.7 陷阱与限制</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">批量 DML 是一把双刃剑：性能极高，但绕过了 JPA 的大量安全机制。以下是生产环境中最常踩的坑。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 11-11 · 批量 DML 的七大陷阱全景</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n① 实体监听器失效\n→ 手动触发审计逻辑\n\n\n② 版本列不自增\n→ setExpression 手动 +1\n\n\n③ JOIN 兼容性\n→ 改用子查询代替 JOIN\n\n\n④ INSERT-SELECT 类型匹配\n→ 确认列顺序和类型\n\n\n⑤ 一级缓存不一致\n→ flush() → DML → clear()\n\n\n⑥ 二级缓存未失效\n→ evict 二级缓存 Region\n\n\n⑦ 事务回滚语义\n→ 合理划分事务边界\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">① 实体监听器失效</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">批量 DML 直接生成 SQL 发送给数据库，完全绕过 JPA 实体生命周期回调。<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@PreUpdate</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@PostDelete</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityListeners</code> 中的审计逻辑（如记录修改人、修改时间）不会被触发。</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 这些监听器在批量 DML 时不会执行</span><br/>@PreUpdate<br/>public void onUpdate() {<br/>    this.updatedBy = SecurityContext.getCurrentUser();<br/>    this.updatedAt = Instant.now();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 解决方案：在批量 UPDATE 中手动 set 审计字段</span><br/>cbf.update(em, Order.class, \"o\")<br/>    .set(\"status\", OrderStatus.ARCHIVED)<br/>    .set(\"updatedBy\", currentUser)           <span style=\"color:#6c7086;font-style:italic;\">// 手动设置</span><br/>    .setExpression(\"updatedAt\", \"CURRENT_TIMESTAMP\")  <span style=\"color:#6c7086;font-style:italic;\">// 手动设置</span><br/>    .where(\"status\").eq(OrderStatus.COMPLETED)<br/>    .executeUpdate();</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">② 版本列不自增</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">JPA 乐观锁依赖 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Version</code> 字段在每次更新时自动递增。批量 UPDATE 绕过了这个机制，版本号不会自动 +1，可能导致后续的乐观锁检查失效。</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ 手动递增版本列</span><br/>cbf.update(em, Order.class, \"o\")<br/>    .set(\"status\", OrderStatus.ARCHIVED)<br/>    .setExpression(\"version\", \"o.version + 1\")  <span style=\"color:#6c7086;font-style:italic;\">// 手动 +1</span><br/>    .where(\"status\").eq(OrderStatus.COMPLETED)<br/>    .executeUpdate();</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">③ JOIN 在 UPDATE/DELETE 中的兼容性</h3></section>\n\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ UPDATE 中直接 JOIN 可能不兼容所有数据库</span><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 推荐：用子查询代替 JOIN</span><br/>cbf.update(em, Order.class, \"o\")<br/>    .set(\"status\", OrderStatus.VIP_ORDER)<br/>    .where(\"o.customer.id\").in()<br/>        .from(Customer.class, \"c\")<br/>        .select(\"c.id\")<br/>        .where(\"c.tier\").eq(CustomerTier.VIP)<br/>    .end()<br/>    .executeUpdate();</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">④ INSERT-SELECT 类型必须精确匹配</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">bind()</code> 的目标列与 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">select()</code> 的源表达式的 Java 类型必须严格一致。<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Integer</code> 对 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Long</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">String</code> 对 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Enum</code> 都会导致运行时类型转换错误。列的绑定顺序也必须与目标表的实际列顺序对应。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">⑤ 二级缓存未失效</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">即使你正确地 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">em.clear()</code> 清空了一级缓存，JPA 二级缓存（如 Hibernate 的 Ehcache / Infinispan）仍然持有旧数据。批量 DML 后需要手动 evict 对应实体的缓存 Region：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 清除 Hibernate 二级缓存中 Order 实体的缓存</span><br/>em.getEntityManagerFactory().getCache()<br/>    .evict(Order.class);</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">⑥ 事务边界与回滚</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">批量 DML 一旦执行就直接写入数据库（在事务内）。如果后续业务逻辑抛出异常导致事务回滚，DML 也会一并回滚——这是正确行为。但要注意：如果你在批量 DML 后发送了外部通知（如邮件、消息队列），回滚无法撤回已发送的通知。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ 副作用不可回滚：</strong>不要在批量 DML 和事务提交之间执行不可逆的外部副作用（发邮件、调用第三方 API、推送消息队列）。将副作用移到事务提交成功后的回调中，使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">TransactionSynchronizationManager.registerSynchronization()</code> 注册 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">afterCommit()</code> 回调。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">⑦ 完整的安全操作清单</h3></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">阶段</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">操作</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">说明</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">DML 前</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">em.flush()</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">写出 pending 变更</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">DML 构建</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">手动 set 审计字段</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">弥补 @PreUpdate 失效</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">DML 构建</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">手动递增 version 列</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">弥补乐观锁失效</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">DML 构建</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">用子查询代替 JOIN</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">确保跨数据库兼容</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">DML 后</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">em.clear()</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">清空一级缓存</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">DML 后</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">cache.evict(Entity.class)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">清除二级缓存</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">事务后</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">afterCommit()</code> 执行副作用</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">避免回滚后的\"幽灵通知\"</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">告别字符串拼接</strong> — Blaze-Persistence 为 UPDATE、DELETE、INSERT-SELECT 提供了类型安全的流式 Builder API，编译时即可发现字段名错误</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">UPDATE CriteriaBuilder</strong> 通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">set()</code> 设字面值、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setExpression()</code> 设表达式、子查询设动态值，支持完整的 WHERE 过滤</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">DELETE CriteriaBuilder</strong> 支持带 EXISTS / IN 子查询的条件删除</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">INSERT-SELECT</strong> 是 JPA 不支持的 Blaze-Persistence 独有能力，适用于数据归档、表间迁移、批量初始化</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">ReturningResult</strong> 在 PostgreSQL / Oracle / SQL Server 上原生支持 RETURNING 子句，其他数据库通过先 SELECT 再 DML 模拟</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">缓存一致性</strong>是批量 DML 的最大风险——必须在 DML 前 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">flush()</code>、DML 后 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">clear()</code> + 二级缓存 evict</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">七大陷阱</strong>：实体监听器失效、版本列不自增、JOIN 兼容性、INSERT-SELECT 类型匹配、一级/二级缓存不一致、事务回滚与副作用</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">下一章 <span style=\"color:#1e6fff;\">第 12 章 · Spring Data 集成</span> 将探讨如何把 CriteriaBuilder 和 Entity View 无缝嵌入 Spring Data Repository 体系——Auto-configuration 自动装配、EntityViewRepository 开箱即用的 CRUD、以及 EntityViewSpecification 的动态查询组合。</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}